    class PriorityQueue[T](comparator: (T, T) => Int) {
        private val heap: Array[T] = Array.ofDim[T](m * n)
        private var size: Int = 0
        private val comp: (T, T) => Int = comparator

        def enqueue(item: T): Unit = {
            size += 1
            heap(size - 1) = item
            var i = size - 1
            while (i > 0) {
                val parent = (i - 1) / 2
                if (comp(heap(i), heap(parent)) >= 0) {
                    swap(i, parent)
                    i = parent
                } else {
                    break
                }
            }
        }

        def dequeue(): T = {
            if (size == 0) throw new NoSuchElementException("Priority queue is empty")
            if (size == 1) {
                size = 0
                return heap(0)
            }
            val item = heap(0)
            heap(0) = heap(size - 1)
            size -= 1
            heapify(0)
            item
        }

        def isEmpty: Boolean = size == 0

        private def swap(i: Int, j: Int): Unit = {
            val temp = heap(i)
            heap(i) = heap(j)
            heap(j) = temp
        }

        private def heapify(i: Int): Unit = {
