    private val heap = mutable.ListBuffer[T]()
    private val comp = comparator

    def enqueue(item: T): Unit = {
        heap += item
        heapifyUp(heap.length - 1)
    }

    def dequeue(): T = {
        if (heap.isEmpty) throw new NoSuchElementException("Queue is empty")
        val item = heap(0)
        heap(0) = heap.last
        heap.remove(heap.length - 1)
        heapifyDown(0)
        item
    }

