    private def heapifyUp(index: Int): Unit = {
        while (index > 0) {
            val parentIndex = (index - 1) / 2
            if (comp(heap(index), heap(parentIndex)) >= 0) {
                val temp = heap(index)
                heap(index) = heap(parentIndex)
                heap(parentIndex) = temp
                index = parentIndex
            } else {
                break
            }
        }
