function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    const dist = Array(m).fill(0).map(() => Array(n).fill(Infinity));
    dist[0][0] = 0;

    const dirs = [[0, 1], [1, 0]]; // right, down

    const pq = new PriorityQueue<[number, number, number, number]>((a, b) => a[0] - b[0]);
    pq.enqueue([0, 0, 0, 0]); // [cost, row, col, usedTeleports]

    while (!pq.isEmpty()) {
        const [cost, row, col, used] = pq.dequeue()!;
        if (row === m - 1 && col === n - 1) return cost;
        if (used > k) continue;

        // Regular move: right or down
        for (const [dr, dc] of dirs) {
            const r = row + dr;
            const c = col + dc;
            if (r < m && c < n) {
                const newCost = cost + grid[r][c];
                if (newCost < dist[r][c]) {
                    dist[r][c] = newCost;
                    pq.enqueue([newCost, r, c, used]);
                }
            }
        }

        // Teleport: find all cells with value <= current cell's value
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (grid[i][j] <= grid[row][col] && i !== row && j !== col) {
                    if (cost < dist[i][j]) {
                        dist[i][j] = cost;
                        pq.enqueue([cost, i, j, used + 1]);
                    }
                }
            }
        }
    }

    return dist[m - 1][n - 1];
}

class PriorityQueue<T> {
    private heap: T[];
    private comparator: (a: T, b: T) => number;

    constructor(comparator: (a: T, b: T) => number) {
        this.heap = [];
        this.comparator = comparator;
    }

    enqueue(item: T): void {
        this.heap.push(item);
        this.heapifyUp(this.heap.length - 1);
    }

    dequeue(): T | undefined {
        if (this.heap.length === 0) return undefined;
        const item = this.heap[0];
        this.heap[0] = this.heap.pop()!;
        this.heapifyDown(0);
        return item;
    }

    isEmpty(): boolean {
        return this.heap.length === 0;
    }

    private heapifyUp(index: number): void {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.comparator(this.heap[index], this.heap[parentIndex]) >= 0) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    private heapifyDown(index: number): void {
        const leftIndex = 2 * index + 1;
        const rightIndex = 2 * index + 2;
        let smallestIndex = index;

        if (leftIndex < this.heap.length && this.comparator(this.heap[leftIndex], this.heap[smallestIndex]) < 0) {
            smallestIndex = leftIndex;
        }

        if (rightIndex < this.heap.length && this.comparator(this.heap[rightIndex], this.heap[smallestIndex]) < 0) {
            smallestIndex = rightIndex;
        }

        if (smallestIndex !== index) {
            [this.heap[index], this.heap[smallestIndex]] = [this.heap[smallestIndex], this.heap[index]];
            this.heapifyDown(smallestIndex);
        }
    }
}

